+					return s, nil
+				},
+			},
+			expectedMode: "nvml",
+			assertValidImage: func(t *testing.T, c *image.CUDA) {
+				require.EqualValues(t, []string{"GPU1"}, c.VisibleDevices())
+			},
+		},
+		{
+			decription: "image with multiple DOCKER_SWARM envars",
+			config: config.Config{
+				AcceptEnvvarUnprivileged: true,
