+				},
+			},
+			expectedMode: "nvml",
+			assertValidImage: func(t *testing.T, c *image.CUDA) {
+				require.EqualValues(t, []string{"GPU1", "GPU2"}, c.VisibleDevices())
+			},
+		},
+	}
+
+	for _, tc := range testCases {
