commit 7f121137f0b1887fd1bb46697385508c3fee0359
Author: Evan Lezar <elezar@nvidia.com>
Date:   Tue Aug 19 20:33:56 2025 +0200

    Allow config sources to be specified for containerd and crio

    By default containerd extracts the current config by running
    the `containerd config dump` command and if that fails
    we read the existing config file.

    This change allows ordering of these sources to be defined as
    we do for the nvidia-ctk runtime configure command.

    Signed-off-by: Evan Lezar <elezar@nvidia.com>
---
 cmd/nvidia-ctk-installer/container/container.go    | 26 ++++++++++++++++++++++
 .../container/runtime/containerd/config_test.go    |  9 ++++++++
 .../container/runtime/containerd/containerd.go     |  7 ++++--
 .../container/runtime/crio/config_test.go          | 12 +++++++++-
 .../container/runtime/crio/crio.go                 |  7 ++++--
 .../container/runtime/runtime.go                   |  9 ++++++++
 6 files changed, 65 insertions(+), 5 deletions(-)

diff --git a/cmd/nvidia-ctk-installer/container/container.go b/cmd/nvidia-ctk-installer/container/container.go
index f37b15da..3dc26949 100644
--- a/cmd/nvidia-ctk-installer/container/container.go
+++ b/cmd/nvidia-ctk-installer/container/container.go
@@ -26,6 +26,7 @@ import (

 	"github.com/NVIDIA/nvidia-container-toolkit/cmd/nvidia-ctk-installer/container/operator"
 	"github.com/NVIDIA/nvidia-container-toolkit/pkg/config/engine"
+	"github.com/NVIDIA/nvidia-container-toolkit/pkg/config/toml"
 )

 const (
@@ -53,6 +54,8 @@ type Options struct {
 	SetAsDefault  bool
 	RestartMode   string
 	HostRootMount string
+
+	ConfigSources []string
 }

 // Configure applies the options to the specified config
@@ -182,3 +185,26 @@ func (o Options) SystemdRestart(service string) error {

 	return nil
 }
+
+// GetConfigLoaders returns the loaders for the requested config sources.
+// Supported config sources can be specified as:
+//
+// * 'file[=path/to/file]': The specified file or the top-level config path is used.
+// * command: The runtime-specific function supplied as an argument is used.
+func (o Options) GetConfigLoaders(commandSourceFunc func(string, string) toml.Loader) ([]toml.Loader, error) {
+	if len(o.ConfigSources) == 0 {
+		return []toml.Loader{toml.Empty}, nil
+	}
+	var loaders []toml.Loader
+	for _, configSource := range o.ConfigSources {
+		switch configSource {
+		case "file":
+			loaders = append(loaders, toml.FromFile(o.TopLevelConfigPath))
+		case "command":
+			loaders = append(loaders, commandSourceFunc(o.HostRootMount, o.ExecutablePath))
+		default:
+			return nil, fmt.Errorf("unsupported config source %q", configSource)
+		}
+	}
+	return loaders, nil
+}
