+package root
+
+import "errors"
+
+type Versioner interface {
+	Version() (string, error)
+}
+
+func FirstOf(v ...Versioner) Versioner {
+	return firstVersion(v)
+}
+
+type firstVersion []Versioner
+
+var _ Versioner = (firstVersion)(nil)
+
+func (f firstVersion) Version() (string, error) {
+	var errs error
+	for _, v := range f {
+		if v == nil {
+			continue
+		}
+		version, err := v.Version()
+		if err == nil {
+			return version, nil
+		}
+
+		errs = errors.Join(errs, err)
+	}
+
+	return "", errs
+}
